export function initialize(sentinelElement, dotNetRef) {
    const observer = new IntersectionObserver(entries => {
        for (const entry of entries) {
            if (entry.isIntersecting) {
                dotNetRef.invokeMethodAsync('OnSentinelVisible');
            }
        }
    }, { rootMargin: '200px' });

    observer.observe(sentinelElement);

    return { observer, sentinelElement };
}

export function dispose(instance) {
    if (instance) {
        instance.observer.unobserve(instance.sentinelElement);
        instance.observer.disconnect();
    }
}

@typeparam TItem
@implements IAsyncDisposable
@inject IJSRuntime JS

<div class="infinite-scroll-container" style="overflow-y:auto; max-height:100%;">
    @foreach (var item in Items)
    {
        @ChildContent(item)
    }

    @if (HasMore)
    {
        <div @ref="sentinelRef" class="infinite-scroll-sentinel"
             style="display:flex; justify-content:center; padding:1rem;">
            @if (isLoading)
            {
                <div class="spinner-border text-primary" role="status">
                    <span class="visually-hidden">Loading...</span>
                </div>
            }
        </div>
    }
</div>

@code {
    [Parameter, EditorRequired]
    public IReadOnlyList<TItem> Items { get; set; } = [];

    [Parameter, EditorRequired]
    public bool HasMore { get; set; }

    [Parameter, EditorRequired]
    public EventCallback OnLoadMore { get; set; }

    [Parameter, EditorRequired]
    public RenderFragment<TItem> ChildContent { get; set; } = default!;

    private ElementReference sentinelRef;
    private IJSObjectReference? module;
    private IJSObjectReference? observerInstance;
    private bool isLoading;
    private DotNetObjectReference<InfiniteScrollList<TItem>>? dotNetRef;

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender && HasMore)
        {
            await SetupObserver();
        }
    }

    private async Task SetupObserver()
    {
        module ??= await JS.InvokeAsync<IJSObjectReference>(
            "import", "./js/infinite-scroll.js");
        dotNetRef ??= DotNetObjectReference.Create(this);
        observerInstance = await module.InvokeAsync<IJSObjectReference>(
            "initialize", sentinelRef, dotNetRef);
    }

    [JSInvokable]
    public async Task OnSentinelVisible()
    {
        if (isLoading || !HasMore) return;

        isLoading = true;
        StateHasChanged();

        await OnLoadMore.InvokeAsync();

        isLoading = false;
        StateHasChanged();
    }

    public async ValueTask DisposeAsync()
    {
        if (module is not null && observerInstance is not null)
        {
            try
            {
                await module.InvokeVoidAsync("dispose", observerInstance);
            }
            catch (JSDisconnectedException) { }
        }

        if (module is not null)
        {
            try { await module.DisposeAsync(); }
            catch (JSDisconnectedException) { }
        }

        dotNetRef?.Dispose();
    }
}

